/* eslint-disable no-console */
// One-time repair: expenses auto-generated by recurring rules before
// referenceId/referenceModel tagging was added only carried the derived
// `reference` string (AUTO-<last6 of ruleId>), not a real link back to the
// rule. That breaks the Recurring page's unpaid-count aggregation and the
// per-rule "pay pending" dialog, which both match on referenceId. This
// backfills referenceId/referenceModel on those older rows by recomputing
// each rule's deterministic reference string and matching against it.
const mongoose = require('mongoose');
require('dotenv').config({ path: require('path').resolve(__dirname, '../../.env') });
const config = require('../config/config');

mongoose
  .connect(config.mongoose.url)
  .then(async () => {
    console.log('Connected to MongoDB');
    const { RecurringExpense, Expense } = require('../models');

    const rules = await RecurringExpense.find({});
    let totalFixed = 0;

    for (const rule of rules) {
      const reference = `AUTO-${rule._id.toString().slice(-6).toUpperCase()}`;
      const result = await Expense.updateMany(
        {
          organizationId: rule.organizationId,
          branchId: rule.branchId,
          reference,
          referenceId: { $exists: false },
        },
        { $set: { referenceId: rule._id, referenceModel: 'RecurringExpense' } }
      );
      if (result.modifiedCount > 0) {
        console.log(` - ${rule.name} (${reference}): backfilled ${result.modifiedCount} expense(s)`);
        totalFixed += result.modifiedCount;
      }
    }

    console.log(`Done. Backfilled referenceId on ${totalFixed} expense(s) across ${rules.length} rule(s).`);
    await mongoose.disconnect();
    process.exit(0);
  })
  .catch((err) => {
    console.error('Backfill failed:', err);
    process.exit(1);
  });
